define i64 @neg_unguarded_sub(i32 %a, i32 %b) {
  %sub = sub nsw i32 %b, %a
  %ext = sext i32 %sub to i64
  ret i64 %ext
}

define i64 @func1(i32 %a, i32 %b) {
entry:
  %spec.select = tail call i32 @llvm.smin.i32(i32 %b, i32 %a)
  %sub = sub nsw i32 %b, %spec.select
  %conv = sext i32 %sub to i64
  ret i64 %conv
}

