define i64 @smin_commutative(i32 %a, i32 %b) {
  %min = call i32 @llvm.smin.i32(i32 %a, i32 %b)
  %sub = sub nsw i32 %a, %min
  %ext = sext i32 %sub to i64
  ret i64 %ext
}

